class Solution:
    def rob(self, nums):
        n = len(nums)
        if n == 1:
            return nums[0]
        # brute force over all subsets with no two circularly-adjacent indices
        best = 0
        for mask in range(1 << n):
            ok = True
            total = 0
            for i in range(n):
                if mask & (1 << i):
                    j = (i + 1) % n
                    if mask & (1 << j):
                        ok = False
                        break
                    total += nums[i]
            if ok:
                best = max(best, total)
        return best

