class Solution:
    def rob(self, nums):
        if len(nums) == 1:
            return nums[0]
        def linear(arr):
            take, skip = 0, 0
            for v in arr:
                take, skip = skip + v, max(take, skip)
            return max(take, skip)
        return max(linear(nums[1:]), linear(nums[:-1]))

