var rob = function(nums) {
    if (nums.length === 1) return nums[0];
    const linear = (arr) => {
        let take = 0, skip = 0;
        for (const v of arr) {
            const newTake = skip + v;
            skip = Math.max(take, skip);
            take = newTake;
        }
        return Math.max(take, skip);
    };
    return Math.max(linear(nums.slice(1)), linear(nums.slice(0, -1)));
};
